window.NZ_OPISY=window.NZ_OPISY||{};window.NZ_OPISY["r"]={"Robert": "<b>Robert</b>, <b>Rupert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, z imienia Hrodebert. Wywodzi się od słów <i>hrod</i> (sława) oraz <i>beraht</i> (jasny, bystry), co oznacza „<i>ten, który jest sławny</i>”, „<i>ten, który żyje w chwale</i>” oraz „<i>ten, który oświeca noce</i>”.", "Rafał": "<b>Rafał</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_semickie\" target=\"_blank\" rel=\"noopener noreferrer\">semickiego</a> wywodzące się od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> słowa רָפָאֵל (<i><a href=\"https://pl.wikipedia.org/wiki/Rafael\" target=\"_blank\" rel=\"noopener noreferrer\">Rafael</a></i>) składającego się z „<i>rofe</i>” (<i>uzdrowiciel/lekarz</i>) i przyrostka \"<i>-el</i>\" (<i>Pan, Bóg</i>), tłumaczone jako <i>Bóg uleczy/uzdrowi</i>.", "Ryszard": "<b>Ryszard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „ten, który jest potężny i bogaty”. W dokumentach po polsku występuje od początku XIII wieku.", "Roman": "<b>Roman</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>Rōmānus</em> – „rzymski”, „Rzymianin”) – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>.", "Radosław": "<b>Radosław</b>, <b>Redosław</b>, <b>Radsław</b>, <b>Redsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Powstało ono jako złożenie dwóch członów: przymiotnikowego <i>Rado-</i> (motywowanego przez: <i>rad</i> – ‘być zadowolonym, chętnym, cieszyć się’; <i>radzić</i> – ‘troszczyć się, dbać o coś’; <i>radzić</i> – ‘udzielać rady’) oraz rzeczownikowego <i>-sław</i> (‘sława’). W Polsce imię to odnotowano po raz pierwszy w 1173 (w zlatynizowanej formie) jako <i>Radozlaus</i>.", "Remigiusz": "<b>Remigiusz</b> – imię męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od łacińskiego rzeczownika <i>remigium</i>, oznaczającego „wiosło”. Znaczenie imienia to: „wioślarz” lub „wytwórca wioseł”. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> występuje od XIV wieku. Wśród imion nadawanych nowo narodzonym dzieciom, Remigiusz w 2017 roku zajmował 101. miejsce w grupie imion męskich.", "Romuald": "<b>Romuald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „ten, który zdobył sławę dzięki swemu panowaniu”.", "Rajmund": "<b>Rajmund</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Znaczy „ten, który jest pod osłoną losu”.", "Rudolf": "<b>Rudolf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Utworzone ze słów „hrod” - sława, chwała i „wolf” - wilk. Imię to zapisywano w Polsce od <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII</a> wieku, m.in. w formach <i>Rodulfus</i>, <i>Rudolfus</i>, <i>Rudolf</i> i <i>Rudulf</i>. Często występowało w rodach panujących Austrii i Niemiec. Jego żeńskimi odpowiednikami są <a href=\"https://pl.wikipedia.org/wiki/Rudolfa\" target=\"_blank\" rel=\"noopener noreferrer\">Rudolfa</a> i <a href=\"https://pl.wikipedia.org/wiki/Rudolfina\" target=\"_blank\" rel=\"noopener noreferrer\">Rudolfina</a>.", "Roland": "<b>Roland</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, prawdopodobnie pochodzenia francuskiego. Może także wywodzić się ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pragerma%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">pragermańskiego</a>, co oznaczałoby wówczas: 'sławny w kraju', 'bohater narodowy'. Najwcześniejszą postacią tego imienia było <i>Hrodland</i>. Imię to nosił bohater <a href=\"https://pl.wikipedia.org/wiki/Pie%C5%9B%C5%84_o_Rolandzie\" target=\"_blank\" rel=\"noopener noreferrer\">Pieśni o Rolandzie</a>. Włoską formą imienia Roland jest Orlando. Orlando jest bohaterem epopei <a href=\"https://pl.wikipedia.org/wiki/Ludovico_Ariosto\" target=\"_blank\" rel=\"noopener noreferrer\">Ludwika Ariosto</a>, pt. <i>Orlando furioso</i> (<a href=\"https://pl.wikipedia.org/wiki/Orland_szalony\" target=\"_blank\" rel=\"noopener noreferrer\">Orland szalony</a>), przełożonej przez <a href=\"https://pl.wikipedia.org/wiki/Piotr_Kochanowski_(1566%E2%80%931620)\" target=\"_blank\" rel=\"noopener noreferrer\">Piotra Kochanowskiego</a> (zm. 1620).", "Roch": "<b>Roch</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, może pochodzić od germańskiego <i>hrok</i> – kruk, wrona. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staro-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">Staro-wysoko-niemiecki</a> rdzeń <i>Roho</i> – „surowy” występował w germańskich imionach dwuczłonowych np. <i>Rochbert</i>, <i>Rochold</i>, <i>Rochwin</i>, <i>Rochwald</i>, których imię to może być skróceniem, lub osobnym utworzonym od staro-wysoko-niemieckiego <i>Rochon</i> – „krzyczeć, wydawać okrzyk wojenny”. W Polsce imię to jest znane co najmniej od <a href=\"https://pl.wikipedia.org/wiki/XV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XV wieku</a>, przy czym należy pamiętać, że było imię germańskie oraz rodzime skrócenie (jak <a href=\"https://pl.wikipedia.org/wiki/Kochan\" target=\"_blank\" rel=\"noopener noreferrer\">Koch</a>) od słowiańskich imion dwuczłonowych na <i>Ro-</i>, <i>Rod-</i> np. <a href=\"https://pl.wikipedia.org/wiki/Rods%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Rodsław</a>. Rocha spieszczano na Roszek, Roszko.", "Richard": "<b>Ryszard</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słowa oznaczającego „ten, który jest potężny i bogaty”. W dokumentach po polsku występuje od początku XIII wieku.", "Roger": "<b>Roger</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od słów oznaczających „sławny dzięki władaniu oszczepem”.", "Radomir": "<b>Radomir</b>, <b>Radomiar</b>, <b>Radmir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Rado-</i> (motywowanego przez <i>rad</i>- „być zadowolonym, chętnym, cieszyć się” lub <i>radzić</i> - „troszczyć się, dbać o coś”) oraz członu <i>-mir</i> („pokój, spokój, dobro”). Może ono oznaczać „tego, który troszczy się o pokój”.", "Rodion": "<b>Herodion</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a>, genetycznie zdrobnienie imienia <i>Heroides</i>, które prawdopodobnie oznacza „pieśń bohatera” od ‘ηρως (<i>heros</i>) „bohater, wojownik” w połączeniu z ωιδη (<i>oide</i>) „pieśń, oda”. Najbardziej znaną postacią o tym imieniu jest <a href=\"https://pl.wikipedia.org/wiki/Herodion_(posta%C4%87_biblijna)\" target=\"_blank\" rel=\"noopener noreferrer\">Herodion</a>, postać biblijna i święty katolicki oraz prawosławny. Od tego imienia (<i>:&#160;Irodion</i>) powstała staroruska forma skrócona (zdrobniała, spieszczona) <i>Rodion</i>, utworzona za pomocą popularnej w imiennictwie zarówno ruskim, jak i polskim techniki ucinania <a href=\"https://pl.wikipedia.org/wiki/Fazy_artykulacyjne_wyrazu\" target=\"_blank\" rel=\"noopener noreferrer\">nagłosu</a>.", "Ruben": "<b>Ruben</b> – imię z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">j. hebrajskiego</a> (<i>רובן</i>) znaczy <b>oto syn</b>. W skali <a href=\"https://pl.wikipedia.org/wiki/Najpopularniejsze_imiona\" target=\"_blank\" rel=\"noopener noreferrer\">najpopularniejszych imion na świecie</a>, w <a href=\"https://pl.wikipedia.org/wiki/Holandia\" target=\"_blank\" rel=\"noopener noreferrer\">Holandii</a> zajmowało 8 miejsce wśród imion męskich (2008). W <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_angielski\" target=\"_blank\" rel=\"noopener noreferrer\">języku angielskim</a> występuje również forma <i>Reuben</i>. Od imienia Ruben pochodzi imię i nazwisko <i>Rubens</i> (od liczby mnogiej imienia Ruben w j. angielskim).", "Renat": "<b>Renat</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „odrodzony na chrzcie”, „urodzony na nowo”.", "Rufin": "<b>Rufin</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, wywodzące się od imienia <a href=\"https://pl.wikipedia.org/wiki/Rufus\" target=\"_blank\" rel=\"noopener noreferrer\">Rufus</a>. Łacińska końcówka <i>-inus</i> oznacza przynależność, stąd znaczeniem imienia jest „przynależący do Rufusa”. W języku polskim nie wystąpiło w średniowieczu.", "Rajnold": "<b>Reginald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze słów oznaczających „ten, który panuje ze zrządzenia losu”. W XVI wieku wystąpiły formy <b>Rejnold</b>, <b>Reinhold</b>, <b>Ronald</b>. Innymi wariantami są imiona <b>Rajnhold</b>, <b>Rajnold</b>, <b>Ronnie</b>.", "Reinhold": "<b>Reginald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze słów oznaczających „ten, który panuje ze zrządzenia losu”. W XVI wieku wystąpiły formy <b>Rejnold</b>, <b>Reinhold</b>, <b>Ronald</b>. Innymi wariantami są imiona <b>Rajnhold</b>, <b>Rajnold</b>, <b>Ronnie</b>.", "Radek": "<b>Radek</b> to męskie chrześcijańskie imię <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskiego</a> pochodzenia. Na świecie występuje jako samodzielne imię pełne lub zdrobnienie imion takich jak m.in. <a href=\"https://pl.wikipedia.org/wiki/Rados%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Radosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Radomir\" target=\"_blank\" rel=\"noopener noreferrer\">Radomir</a>, <a href=\"https://pl.wikipedia.org/wiki/Radowan\" target=\"_blank\" rel=\"noopener noreferrer\">Radowan</a>, Ctirad.", "Ralf": "<b>Randolf, Ralf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> i oznacza wilczą tarczę. Obchodzi imieniny <a href=\"https://pl.wikipedia.org/wiki/22_lutego\" target=\"_blank\" rel=\"noopener noreferrer\">22 lutego</a> i <a href=\"https://pl.wikipedia.org/wiki/17_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">17 czerwca</a>.", "Radzisław": "<b>Radzisław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, nienotowane w słownikach staropolskich. Człon <i>Radzi-</i> jest niespotykany w staropolskich imionach dwuczłonowych.", "Ran": "<b>Ran</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;らん, ラン) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, a także hebrajskie imię męskie (hebr. רן) oznaczające „radość”.", "Ralph": "<b>Randolf, Ralf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> i oznacza wilczą tarczę. Obchodzi imieniny <a href=\"https://pl.wikipedia.org/wiki/22_lutego\" target=\"_blank\" rel=\"noopener noreferrer\">22 lutego</a> i <a href=\"https://pl.wikipedia.org/wiki/17_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">17 czerwca</a>.", "Radzimir": "<b>Racimir</b>, <b>Racimiar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Raci-</i> (\"walczyć, wojować\") oraz <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"walczący o pokój\".", "Rościsław": "<b>Rościsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członów <i>Rości-</i> (\"rośnie\") oraz <i>-sław</i> (\"sława\"). Może oznaczać \"ten, którego sława rośnie\". Od tego imienia mogły pochodzić formy skrócone typu <a href=\"https://pl.wikipedia.org/wiki/Ros%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Rosław</a>. Podobne imię to <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bcigniew\" target=\"_blank\" rel=\"noopener noreferrer\">Rościgniew</a>.", "Radomił": "<b>Radomił</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie imię</a> męskie, złożone z członu <i>Rado-</i> (motywowany przez <i>rad</i> – „być zadowolonym, chętnym, cieszyć się” lub <i>radzić</i> – „troszczyć się, dbać o coś”) oraz członu <i>-mił</i> („miły”). Może ono oznaczać „tego, który chętnie jest miły”.", "Rusłan": "<b>Rusłan</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Руслан (<i>Rusłán</i>); dawniej także <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Еруслан (<i>Jerusłán</i>)) – rosyjskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, zapożyczone z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_tureckie\" target=\"_blank\" rel=\"noopener noreferrer\">języków tureckich</a>, gdzie występuje pod postaciami <i>Arslan</i>, <i>Aryslan</i> itp. Dosłownie znaczy „lew” (por. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_tatarski\" target=\"_blank\" rel=\"noopener noreferrer\">tatar.</a>&#160;арыслан (<i>aryslan</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_czuwaski\" target=\"_blank\" rel=\"noopener noreferrer\">czuw.</a>&#160;арӑслан (<i>arăslan</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_kazachski\" target=\"_blank\" rel=\"noopener noreferrer\">kaz.</a>&#160;арыстан (<i>arystan</i>), <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_turecki\" target=\"_blank\" rel=\"noopener noreferrer\">tur.</a>&#160;<em>arslan</em> itd.).", "Recep": "<b>Recep</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ludy_tureckie\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, pochodzi od arabskiego imienia <i>Radżab</i>. Na początku XXI wieku noszone przez ok. 17.000 osób.", "Reginald": "<b>Reginald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze słów oznaczających „ten, który panuje ze zrządzenia losu”. W XVI wieku wystąpiły formy <b>Rejnold</b>, <b>Reinhold</b>, <b>Ronald</b>. Innymi wariantami są imiona <b>Rajnhold</b>, <b>Rajnold</b>, <b>Ronnie</b>.", "Rustem": "<b>Rostam Farrochzad</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">pers</a>. رستم فرّخزاد, zm. <a href=\"https://pl.wikipedia.org/wiki/636\" target=\"_blank\" rel=\"noopener noreferrer\">636</a>) – <a href=\"https://pl.wikipedia.org/wiki/Spahbod\" target=\"_blank\" rel=\"noopener noreferrer\">spahbod</a> (naczelny dowódca) armii <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Iran\" target=\"_blank\" rel=\"noopener noreferrer\">perskiej</a> za panowania <a href=\"https://pl.wikipedia.org/wiki/Jezdegerd_III\" target=\"_blank\" rel=\"noopener noreferrer\">Jazdegirda III</a>. Z pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ormianie\" target=\"_blank\" rel=\"noopener noreferrer\">Ormianin</a>, wraz z bratem wiernie służył jednak <a href=\"https://pl.wikipedia.org/wiki/Sasanidzi\" target=\"_blank\" rel=\"noopener noreferrer\">Sasanidom</a>. W roku 636 otrzymał rozkaz zahamowania inwazji <a href=\"https://pl.wikipedia.org/wiki/Arabowie\" target=\"_blank\" rel=\"noopener noreferrer\">Arabów</a>. Nękany proroczymi snami, wyruszył dopiero po interwencji <a href=\"https://pl.wikipedia.org/wiki/Kr%C3%B3l\" target=\"_blank\" rel=\"noopener noreferrer\">królewskiej</a>. Poniósł klęskę i śmierć pod <a href=\"https://pl.wikipedia.org/wiki/Al-Kadisijja_(miasto)\" target=\"_blank\" rel=\"noopener noreferrer\">Kadisijją</a>.", "Romani": "<b>Język romski</b> lub <b>romani</b> (nazwa własna: <em>romani čhib</em>, <em>romani ćhib</em>, w innych językach często określany potoczną nazwą „język cygański”) – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_(mowa)\" target=\"_blank\" rel=\"noopener noreferrer\">język</a> <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoeuropejski</a> z gałęzi <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_nowoindoaryjskie\" target=\"_blank\" rel=\"noopener noreferrer\">nowoindyjskiej</a> języków <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoaryjskie\" target=\"_blank\" rel=\"noopener noreferrer\">indoaryjskich</a>. Romani jest jedynym <a href=\"https://pl.wikipedia.org/wiki/Autochton\" target=\"_blank\" rel=\"noopener noreferrer\">autochtonicznym</a> językiem indoaryjskim używanym w <a href=\"https://pl.wikipedia.org/wiki/Europa\" target=\"_blank\" rel=\"noopener noreferrer\">Europie</a>. Wywodzi się z <a href=\"https://pl.wikipedia.org/wiki/Sanskryt\" target=\"_blank\" rel=\"noopener noreferrer\">sanskrytu</a> za pośrednictwem <a href=\"https://pl.wikipedia.org/wiki/Prakryty\" target=\"_blank\" rel=\"noopener noreferrer\">języków prakryckich</a>. Posługują się nim <a href=\"https://pl.wikipedia.org/wiki/Romowie\" target=\"_blank\" rel=\"noopener noreferrer\">Romowie</a> oraz <a href=\"https://pl.wikipedia.org/wiki/Sinti\" target=\"_blank\" rel=\"noopener noreferrer\">Sinti</a>. Romani nie należy natomiast do grupy <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_roma%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">języków romańskich</a> (przypadkowa zbieżność nazw), w związku z czym tylko w niewielkim stopniu jest spokrewniony z takimi językami jak <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rumu%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">rumuński</a> czy <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_romansz\" target=\"_blank\" rel=\"noopener noreferrer\">romansz</a>.", "Rajnhold": "<b>Reginald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze słów oznaczających „ten, który panuje ze zrządzenia losu”. W XVI wieku wystąpiły formy <b>Rejnold</b>, <b>Reinhold</b>, <b>Ronald</b>. Innymi wariantami są imiona <b>Rajnhold</b>, <b>Rajnold</b>, <b>Ronnie</b>.", "Rajner": "<b>Rajner</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (Ragnar&#65279;<a href=\"https://www.wikidata.org/wiki/Q2127308#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>), znane w Polsce od średniowiecza. Istnieją liczni święci o tym imieniu.", "Ramzes": "<b>Ramzes</b>, <b>Ramesses</b> to <a href=\"https://pl.wikipedia.org/wiki/Staro%C5%BCytny_Egipt\" target=\"_blank\" rel=\"noopener noreferrer\">starożytne egipskie</a> imię, oznaczające <i>zrodził go <a href=\"https://pl.wikipedia.org/wiki/Ra_(b%C3%B3g)\" target=\"_blank\" rel=\"noopener noreferrer\">Ra</a></i>.", "Ronnie": "<b>Reginald</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się ze słów oznaczających „ten, który panuje ze zrządzenia losu”. W XVI wieku wystąpiły formy <b>Rejnold</b>, <b>Reinhold</b>, <b>Ronald</b>. Innymi wariantami są imiona <b>Rajnhold</b>, <b>Rajnold</b>, <b>Ronnie</b>.", "Rabin": "<b>Rabin</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a>&#160;&#8207;רַבִּי&#8206;, <i>rabbī</i> lub רַב, <i>raw</i>) – podstawowa funkcja <a href=\"https://pl.wikipedia.org/wiki/Religia\" target=\"_blank\" rel=\"noopener noreferrer\">religijna</a> w <a href=\"https://pl.wikipedia.org/wiki/Judaizm\" target=\"_blank\" rel=\"noopener noreferrer\">judaizmie</a>. <i>Rabbi</i> to <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskie</a> słowo oznaczające mistrza i nauczyciela.", "Radosz": "<b>Radosław</b>, <b>Redosław</b>, <b>Radsław</b>, <b>Redsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Powstało ono jako złożenie dwóch członów: przymiotnikowego <i>Rado-</i> (motywowanego przez: <i>rad</i> – ‘być zadowolonym, chętnym, cieszyć się’; <i>radzić</i> – ‘troszczyć się, dbać o coś’; <i>radzić</i> – ‘udzielać rady’) oraz rzeczownikowego <i>-sław</i> (‘sława’). W Polsce imię to odnotowano po raz pierwszy w 1173 (w zlatynizowanej formie) jako <i>Radozlaus</i>.", "Rifat": "Przez <a href=\"https://pl.wikipedia.org/wiki/J%C3%B3zef_Flawiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Józefa Flawiusza</a> uważany był za praojca mieszkańców <a href=\"https://pl.wikipedia.org/wiki/Paflagonia\" target=\"_blank\" rel=\"noopener noreferrer\">Paflagonii</a>. Jego imię łączono ze wzmiankowanymi w źródłach starożytnych <a href=\"https://pl.wikipedia.org/wiki/G%C3%B3ry_Ryfejskie\" target=\"_blank\" rel=\"noopener noreferrer\">Górami Ryfejskimi</a>, August Wilhelm Knobel wywodził od niego genealogię <a href=\"https://pl.wikipedia.org/wiki/Celtowie\" target=\"_blank\" rel=\"noopener noreferrer\">Celtów</a>. W <a href=\"https://pl.wikipedia.org/wiki/XVI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVI</a> i <a href=\"https://pl.wikipedia.org/wiki/XVII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVII-wiecznych</a> źródłach ruskich (m.in. w <i><a href=\"https://pl.wikipedia.org/wiki/Latopis_Husty%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">Latopisie Hustyńskim</a></i>) Rifat wymieniany jest jako przodek <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_zachodni\" target=\"_blank\" rel=\"noopener noreferrer\">Słowian zachodnich</a> i <a href=\"https://pl.wikipedia.org/wiki/S%C5%82owianie_po%C5%82udniowi\" target=\"_blank\" rel=\"noopener noreferrer\">południowych</a> lub ogólnie wszystkich ludów słowiańskich.", "Remus": "<b>Remus</b> – <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie obcego, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">nieindoeuropejskiego</a> pochodzenia i o niejasnym znaczeniu. Imię <a href=\"https://pl.wikipedia.org/wiki/Romulus_i_Remus\" target=\"_blank\" rel=\"noopener noreferrer\">jednego z dwóch legendarnych założycieli Rzymu</a>.", "Rufus": "<b>Rufus</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>. Wywodzi się od słowa oznaczającego „rudowłosy”. Istniało kilkunastu świętych o tym imieniu.", "Rana": "W zależności od sposobu działania siły, mechanizmu jej działania, rozróżnia się klasyczne typy rany: <a href=\"https://pl.wikipedia.org/wiki/Rana_ci%C4%99ta\" target=\"_blank\" rel=\"noopener noreferrer\">cięte</a>, <a href=\"https://pl.wikipedia.org/wiki/Rana_k%C5%82uta\" target=\"_blank\" rel=\"noopener noreferrer\">kłute</a>, <a href=\"https://pl.wikipedia.org/wiki/Rana_postrza%C5%82owa\" target=\"_blank\" rel=\"noopener noreferrer\">postrzałowe</a>, <a href=\"https://pl.wikipedia.org/wiki/Rana_t%C5%82uczona\" target=\"_blank\" rel=\"noopener noreferrer\">tłuczone</a>, <a href=\"https://pl.wikipedia.org/wiki/Rana_szarpana\" target=\"_blank\" rel=\"noopener noreferrer\">szarpane</a>, <a href=\"https://pl.wikipedia.org/wiki/Rana_k%C4%85sana\" target=\"_blank\" rel=\"noopener noreferrer\">kąsane</a>. Często uszkodzeniom <a href=\"https://pl.wikipedia.org/wiki/Sk%C3%B3ra\" target=\"_blank\" rel=\"noopener noreferrer\">skóry</a> i <a href=\"https://pl.wikipedia.org/wiki/Nask%C3%B3rek\" target=\"_blank\" rel=\"noopener noreferrer\">naskórka</a> towarzyszą uszkodzenia tkanek głębiej położonych: powięzi, <a href=\"https://pl.wikipedia.org/wiki/Mi%C4%99sie%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">mięśni</a>, naczyń krwionośnych, <a href=\"https://pl.wikipedia.org/wiki/Nerw\" target=\"_blank\" rel=\"noopener noreferrer\">nerwów</a>, <a href=\"https://pl.wikipedia.org/wiki/%C5%9Aci%C4%99gno\" target=\"_blank\" rel=\"noopener noreferrer\">ścięgien</a>, <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">kości</a>, <a href=\"https://pl.wikipedia.org/wiki/Staw_(anatomia)\" target=\"_blank\" rel=\"noopener noreferrer\">stawów</a>. Obecność dodatkowych uszkodzeń ma istotne znaczenie dla procesu gojenia rany. Uraz o niedużej sile może nie uszkodzić wszystkich warstw skóry, uszkadzając tylko jej powierzchniową warstwę – <a href=\"https://pl.wikipedia.org/wiki/Nask%C3%B3rek\" target=\"_blank\" rel=\"noopener noreferrer\">naskórek</a> – powodując powstanie <a href=\"https://pl.wikipedia.org/wiki/Otarcie\" target=\"_blank\" rel=\"noopener noreferrer\">otarcia</a> lub wywołując <a href=\"https://pl.wikipedia.org/wiki/St%C5%82uczenie\" target=\"_blank\" rel=\"noopener noreferrer\">stłuczenie</a> tkanek.", "Rodryg": "<b>Roderyk, Rodryg, Rodryk, Ruderyk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia germańskiego. Wywodzi się od słowa oznaczającego „sławny ze swego bogactwa” lub „sławny król”.", "Rubin": "<b>Rubin</b> – <a href=\"https://pl.wikipedia.org/wiki/Kamienie_szlachetne\" target=\"_blank\" rel=\"noopener noreferrer\">kamień szlachetny</a> o barwie od różowawo-czerwonej do krwistoczerwonej, odmiana <a href=\"https://pl.wikipedia.org/wiki/Korund\" target=\"_blank\" rel=\"noopener noreferrer\">korundu</a>, chemicznie <a href=\"https://pl.wikipedia.org/wiki/Tritlenek_diglinu\" target=\"_blank\" rel=\"noopener noreferrer\">tritlenek diglinu</a>. Jego nazwa pochodzi od czerwonej barwy (z <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>rubens</em>).", "Rosław": "<b>Rosław</b> – słowiańskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, będące formą skróconą imienia <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bcis%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Rościsław</a> lub <a href=\"https://pl.wikipedia.org/wiki/Rods%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Rodsław</a>.", "Roma": "<b>Roma</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię żeńskie</a>, które stanowi skróconą postać imienia <a href=\"https://pl.wikipedia.org/wiki/Romana_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Romana</a> lub <a href=\"https://pl.wikipedia.org/wiki/Romualda\" target=\"_blank\" rel=\"noopener noreferrer\">Romualda</a>; niekiedy bywa nadawane jako samodzielne imię.", "Radmir": "<b>Radomir</b>, <b>Radomiar</b>, <b>Radmir</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Rado-</i> (motywowanego przez <i>rad</i>- „być zadowolonym, chętnym, cieszyć się” lub <i>radzić</i> - „troszczyć się, dbać o coś”) oraz członu <i>-mir</i> („pokój, spokój, dobro”). Może ono oznaczać „tego, który troszczy się o pokój”.", "Rabi": "<b>Rabi</b> (z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i>mój mistrz</i>) – tytuł honorowy, którym uczniowie obdarzali <a href=\"https://pl.wikipedia.org/wiki/Babilonia\" target=\"_blank\" rel=\"noopener noreferrer\">babilońskich</a> <a href=\"https://pl.wikipedia.org/wiki/Amoraici\" target=\"_blank\" rel=\"noopener noreferrer\">amoraitów</a>. Od tego słowa pochodzą późniejsze określenia i zwroty grzecznościowe typu <a href=\"https://pl.wikipedia.org/wiki/Rabin\" target=\"_blank\" rel=\"noopener noreferrer\">rabin</a>, <a href=\"https://pl.wikipedia.org/wiki/Reb\" target=\"_blank\" rel=\"noopener noreferrer\">reb</a> czy <a href=\"https://pl.wikipedia.org/wiki/Rebe\" target=\"_blank\" rel=\"noopener noreferrer\">rebe</a>.", "Roderyk": "<b>Roderyk, Rodryg, Rodryk, Ruderyk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia germańskiego. Wywodzi się od słowa oznaczającego „sławny ze swego bogactwa” lub „sławny król”.", "Rodryk": "<b>Roderyk, Rodryg, Rodryk, Ruderyk</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia germańskiego. Wywodzi się od słowa oznaczającego „sławny ze swego bogactwa” lub „sławny król”.", "Racibor": "<b>Racibor</b>, <b>Raciborz</b>, <b>Recibor</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Raci-</i> („wojna”, „walczyć, wojować”) oraz <i>-bor</i> („walczyć, zmagać się”). Mogło oznaczać „walczący w wielu wojnach”. Od imienia pochodzi nazwa miasta <a href=\"https://pl.wikipedia.org/wiki/Racib%C3%B3rz\" target=\"_blank\" rel=\"noopener noreferrer\">Racibórz</a>.", "Ren": "<b>Ren</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;れん, レン) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a> noszone zarówno przez kobiety jak i przez mężczyzn.", "Riku": "<b>Riku</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;りく, リク) – głównie męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>, sporadycznie noszone przez kobiety, oraz fińskie zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Ryszard\" target=\"_blank\" rel=\"noopener noreferrer\">Ryszarda</a>.", "Radzimierz": "<b>Racimir</b>, <b>Racimiar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Raci-</i> (\"walczyć, wojować\") oraz <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"walczący o pokój\".", "Romulus": "<b>Romulus</b> – <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie obcego, <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_indoeuropejskie\" target=\"_blank\" rel=\"noopener noreferrer\">nieindoeuropejskiego</a> pochodzenia według niektórych źródeł; według innych stanowi ono spieszczenie imienia (dawniej <a href=\"https://pl.wikipedia.org/wiki/Nazwisko#Przydomek_(cognomen)\" target=\"_blank\" rel=\"noopener noreferrer\">przydomka</a>) <a href=\"https://pl.wikipedia.org/wiki/Roman_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Roman</a>, oznaczającego \"rzymski\". Było to imię <a href=\"https://pl.wikipedia.org/wiki/Romulus_i_Remus\" target=\"_blank\" rel=\"noopener noreferrer\">legendarnego założyciela Rzymu</a>. Patronem tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Romulus_(biskup_Fiesole)\" target=\"_blank\" rel=\"noopener noreferrer\">św. Romulus</a>, męczennik z <a href=\"https://pl.wikipedia.org/wiki/IV_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">IV wieku</a>.", "Radowit": "<b>Radowit</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Rado-</i> (\"rad\") i <i>-wit</i> (\"pan, władca\"). Znaczenie imienia: \"rad swemu władcy\" albo \"ten, któremu jest rad jego władca\".", "Rok": "<b>Rok</b> – wspólna nazwa różnych <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostek miar</a>, zwykle <a href=\"https://pl.wikipedia.org/wiki/Czas\" target=\"_blank\" rel=\"noopener noreferrer\">czasu</a>; może oznaczać:", "Randolf": "<b>Randolf, Ralf</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się z języka <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staronordyjski\" target=\"_blank\" rel=\"noopener noreferrer\">staronordyjskiego</a> i oznacza wilczą tarczę. Obchodzi imieniny <a href=\"https://pl.wikipedia.org/wiki/22_lutego\" target=\"_blank\" rel=\"noopener noreferrer\">22 lutego</a> i <a href=\"https://pl.wikipedia.org/wiki/17_czerwca\" target=\"_blank\" rel=\"noopener noreferrer\">17 czerwca</a>.", "Radogost": "<b>Radogost</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie o konstrukcji typowej dla <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imion słowiańskich</a>, niepoświadczone w dawnych źródłach polskich. Znaczenie imienia: „rad gościom (obcym)”. Jest odwróceniem imienia <a href=\"https://pl.wikipedia.org/wiki/Go%C5%9Bcirad\" target=\"_blank\" rel=\"noopener noreferrer\">Gościrad</a>. Jest to prawdopodobnie jedno z najwcześniej zapisanych imion słowiańskich (w formie <a href=\"https://pl.wikipedia.org/wiki/Ardagast\" target=\"_blank\" rel=\"noopener noreferrer\">Ardagast</a> w VI wieku n.e. – jeśli nie chodziło o inne imię). Zachowało się w formie nazw miejscowości.", "Ronin": "<b>Rōnin</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;浪人) – w dosłownym tłumaczeniu z języka japońskiego słowo <i>rōnin</i> oznacza człowieka-falę, który, tak jak ona, toczy się tam, dokąd wieje wiatr (dokąd powiedzie go los).", "R": "<b>R</b> (<i>er</i>, <a href=\"https://pl.wikipedia.org/wiki/Minusku%C5%82a\" target=\"_blank\" rel=\"noopener noreferrer\">minuskuła</a>: <b>r</b>) – osiemnasta litera <a href=\"https://pl.wikipedia.org/wiki/Alfabet_%C5%82aci%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu łacińskiego</a> i dwudziesta trzecia <a href=\"https://pl.wikipedia.org/wiki/Alfabet_polski\" target=\"_blank\" rel=\"noopener noreferrer\">alfabetu polskiego</a>. Oznacza zwykle w danym języku spółgłoskę <a href=\"https://pl.wikipedia.org/wiki/Rotyczno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">rotyczną</a>, np. [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_dr%C5%BC%C4%85ca_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">r</a>], [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_uderzeniowa_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ɾ</a>] lub [<a href=\"https://pl.wikipedia.org/wiki/Sp%C3%B3%C5%82g%C5%82oska_p%C3%B3%C5%82otwarta_dzi%C4%85s%C5%82owa_d%C5%BAwi%C4%99czna\" target=\"_blank\" rel=\"noopener noreferrer\">ɹ</a>].", "Rymwid": "<b>Rymwid</b> – funkcjonujący jako <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia literackiego, przydomek rodziny <a href=\"https://pl.wikipedia.org/wiki/Adam_Mickiewicz\" target=\"_blank\" rel=\"noopener noreferrer\">Mickiewiczów</a> o nieznanej <a href=\"https://pl.wikipedia.org/wiki/Etymologia\" target=\"_blank\" rel=\"noopener noreferrer\">etymologii</a>. Być może stanowił on rzeczywiście imię męskie i, tak jak w przypadku imienia Moniwid, powstało ono przez dodanie <a href=\"https://pl.wikipedia.org/wiki/Przyrostek\" target=\"_blank\" rel=\"noopener noreferrer\">sufiksoidu</a> <i>–vid</i> (por. <i>vyd–</i> lit. <i>išvýsti</i>, <i>isvýdo</i> – „zobaczyć, spostrzec”) do pierwszego członu <i>Rim–</i>, który w tym przypadku stanowiłby skróconą formę <i>Rimis</i> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_gocki\" target=\"_blank\" rel=\"noopener noreferrer\">goc.</a> <i>rimis</i> – „spokój, cisza”) – pierwszego członu <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskich</a> imion złożonych.", "Radzim": "<b>Radzim</b> – forma skrócona od staropolskich <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> męskich, rozpoczynających się od członu <i>Rado-</i> (motywowanego przez <i>rad</i> – \"być zadowolonym, chętnym, cieszyć się\" lub <i>radzić</i> – \"troszczyć się, dbać o coś\"). Uważa się, że imię to jest odpowiednikiem znaczeniowym imienia <a href=\"https://pl.wikipedia.org/wiki/Gaudenty_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Gaudenty</a> – \"radosny\".", "Radost": "<b>Radosław</b>, <b>Redosław</b>, <b>Radsław</b>, <b>Redsław</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie imię</a> męskie. Powstało ono jako złożenie dwóch członów: przymiotnikowego <i>Rado-</i> (motywowanego przez: <i>rad</i> – ‘być zadowolonym, chętnym, cieszyć się’; <i>radzić</i> – ‘troszczyć się, dbać o coś’; <i>radzić</i> – ‘udzielać rady’) oraz rzeczownikowego <i>-sław</i> (‘sława’). W Polsce imię to odnotowano po raz pierwszy w 1173 (w zlatynizowanej formie) jako <i>Radozlaus</i>.", "Rafa": "W zależności od pochodzenia rafa może być:", "Raszyd": "<b>Raszyd</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> رشيد lub راشد) – to męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arabskiego</a>, znaczy „prawy, sprawiedliwy”. Żeńską formą tego imienia jest<b> Raszyda</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_arabski\" target=\"_blank\" rel=\"noopener noreferrer\">arab.</a> راشدة lub رشيدة).", "Ryutaro": "<b>Ryūtarō</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;りゅうたろう, リュウタロウ) – męskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Radowan": "<b>Radowan</b>, <b>Radwan</b>, <b>Redwan</b> – <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_staropolski\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a>/<a href=\"https://pl.wikipedia.org/wiki/S%C5%82owia%C5%84szczyzna\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_pras%C5%82owia%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">psł.</a> <i>*radovati (sę)</i>, <i>radъ</i> - radować (się), (być) rad. Znaczenie imienia: „radujący się”. Współcześnie popularne imię czeskie i południowosłowiańskie w pisowni Radovan, cyrylickie Радован. Co do imion złożonych z <a href=\"https://pl.wikipedia.org/wiki/Morfem\" target=\"_blank\" rel=\"noopener noreferrer\">morfemem</a> <i>Rado</i>: <a href=\"https://pl.wikipedia.org/wiki/Radociech\" target=\"_blank\" rel=\"noopener noreferrer\">Radociech</a>, <a href=\"https://pl.wikipedia.org/wiki/Rados%C5%82aw_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Radosław</a>, <a href=\"https://pl.wikipedia.org/wiki/Radomi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Radomił</a>, Radomier, <a href=\"https://pl.wikipedia.org/wiki/Radomir\" target=\"_blank\" rel=\"noopener noreferrer\">Radomir</a>, <a href=\"https://pl.wikipedia.org/wiki/Radowit\" target=\"_blank\" rel=\"noopener noreferrer\">Radowit</a>, <a href=\"https://pl.wikipedia.org/wiki/Radowuj\" target=\"_blank\" rel=\"noopener noreferrer\">Radowuj</a>, <a href=\"https://pl.wikipedia.org/wiki/Cieszyrad\" target=\"_blank\" rel=\"noopener noreferrer\">Cieszyrad</a>, <a href=\"https://pl.wikipedia.org/wiki/Bogurad\" target=\"_blank\" rel=\"noopener noreferrer\">Bogurad</a>, <a href=\"https://pl.wikipedia.org/wiki/Go%C5%9Bcirad\" target=\"_blank\" rel=\"noopener noreferrer\">Gościrad</a> etc. to w grę może wchodzić również pochodzenie od staropolskiego <i>radzić</i> „troszczyć, dbać o coś”, od psł. <i>*raditi</i> lub <i>radzić</i> „udzielać rady” <a href=\"https://pl.wikipedia.org/wiki/Zapo%C5%BCyczenia_j%C4%99zykowe\" target=\"_blank\" rel=\"noopener noreferrer\">zapożyczonego</a> ze <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_%C5%9Brednio-wysoko-niemiecki\" target=\"_blank\" rel=\"noopener noreferrer\">śwn.</a> <i>raden</i>.", "Reuel": "<b>Reuel</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> רְעוּאֵל - <i>Bóg jest pasterzem</i>) – hebrajskie imię noszone przez kilka biblijnych postaci.", "Rodrigues": "Liczba ludności w 2014 wynosiła 41 669. Głównym językiem jest <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_francuski\" target=\"_blank\" rel=\"noopener noreferrer\">francuski</a>, a główną religią <a href=\"https://pl.wikipedia.org/wiki/Katolicyzm\" target=\"_blank\" rel=\"noopener noreferrer\">katolicyzm</a>. Większość mieszkańców jest pochodzenia afrykańskiego, jest też trochę osób pochodzenia europejskiego, indyjskiego i chińskiego.", "Racimir": "<b>Racimir</b>, <b>Racimiar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Raci-</i> (\"walczyć, wojować\") oraz <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"walczący o pokój\".", "Radym": "<b>Radym</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">ros.</a>&#160;Радим) – według <i><a href=\"https://pl.wikipedia.org/wiki/Powie%C5%9B%C4%87_minionych_lat\" target=\"_blank\" rel=\"noopener noreferrer\">Powieści minionych lat</a></i> protoplasta i eponim plemienia <a href=\"https://pl.wikipedia.org/wiki/Radymicze\" target=\"_blank\" rel=\"noopener noreferrer\">Radymiczów</a>. Miał być bratem <a href=\"https://pl.wikipedia.org/wiki/Wiatko\" target=\"_blank\" rel=\"noopener noreferrer\">Wiatki</a>; oboje pochodzili z plemienia <a href=\"https://pl.wikipedia.org/wiki/Plemiona_lechickie\" target=\"_blank\" rel=\"noopener noreferrer\">Lachów</a>. Wraz ze swoim rodem osiadł nad rzeką <a href=\"https://pl.wikipedia.org/wiki/So%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">Sożą</a>, dając początek plemieniu nazwanemu od jego imienia.", "Radha": "<b>Radha</b> (<a href=\"https://pl.wikipedia.org/wiki/Pismo_dewanagari\" target=\"_blank\" rel=\"noopener noreferrer\">dewanagari</a> राधा) <i>(także Radharani)</i> – w <a href=\"https://pl.wikipedia.org/wiki/Hinduizm\" target=\"_blank\" rel=\"noopener noreferrer\">hinduizmie</a> córka Wriśabanu i Kirti, ukochana <a href=\"https://pl.wikipedia.org/wiki/Gopi\" target=\"_blank\" rel=\"noopener noreferrer\">gopi</a> <a href=\"https://pl.wikipedia.org/wiki/Kryszna_(b%C3%B3g)\" target=\"_blank\" rel=\"noopener noreferrer\">Kryszny</a>. W <a href=\"https://pl.wikipedia.org/wiki/Wisznuizm\" target=\"_blank\" rel=\"noopener noreferrer\">wisznuizmie</a> (<a href=\"https://pl.wikipedia.org/wiki/Krysznaizm\" target=\"_blank\" rel=\"noopener noreferrer\">krysznaizmie</a>) uważa się, że Radha i Kryszna są jednością w dwóch formach (Radha jest emanacją Kryszny tożsamą z nim). Wisznuici uważają, że dla osiągnięcia najwyższej formy doskonałości (raganuga) konieczne jest znalezienie <a href=\"https://pl.wikipedia.org/wiki/Guru\" target=\"_blank\" rel=\"noopener noreferrer\">guru</a>, który jest w pełni oddany Radharani.", "Romeusz": "<b>Romeusz</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_w%C5%82oski\" target=\"_blank\" rel=\"noopener noreferrer\">wł.</a> <i>Romeo</i>) – późnorzymskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, oznaczające pierwotnie pielgrzyma zmierzającego do <a href=\"https://pl.wikipedia.org/wiki/Rzym\" target=\"_blank\" rel=\"noopener noreferrer\">Rzymu</a>.", "Ruyi": "<b>Ruyi</b> (dosł. <i>zgodnie z życzeniem</i>) – <a href=\"https://pl.wikipedia.org/wiki/Chiny\" target=\"_blank\" rel=\"noopener noreferrer\">chińskie</a> <a href=\"https://pl.wikipedia.org/wiki/Ber%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">berło</a>, w przeciwieństwie do swojego europejskiego odpowiednika niebędące jednak atrybutem władzy, a <a href=\"https://pl.wikipedia.org/wiki/Talizman\" target=\"_blank\" rel=\"noopener noreferrer\">talizmanem</a> mającym zapewnić szczęście i spełnienie marzeń.", "Reiko": "<b>Reiko</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;れいこ, レイコ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Rosalin": "Nazwa pochodzi od dawnej nazwy północnej części Norwegii (legendarnej wyspy) – Thule, gdzie minerał ten występuje.", "Rano": "<b>Poranek</b>, także <b>ranek</b> lub <b>rano</b> – dający się obiektywnie wyróżnić moment w ciągu <a href=\"https://pl.wikipedia.org/wiki/Doba\" target=\"_blank\" rel=\"noopener noreferrer\">doby</a> jako wczesna część <a href=\"https://pl.wikipedia.org/wiki/Dzie%C5%84\" target=\"_blank\" rel=\"noopener noreferrer\">dnia</a> (pora dnia), mająca miejsce około <a href=\"https://pl.wikipedia.org/wiki/Wsch%C3%B3d_S%C5%82o%C5%84ca\" target=\"_blank\" rel=\"noopener noreferrer\">wschodu słońca</a> i trwająca do <a href=\"https://pl.wikipedia.org/wiki/Po%C5%82udnie_(12:00)\" target=\"_blank\" rel=\"noopener noreferrer\">południa</a>; <a href=\"https://pl.wikipedia.org/wiki/Okolicznik\" target=\"_blank\" rel=\"noopener noreferrer\">Okolicznik</a> czasu definiujący początek dnia – czas gdy zaczyna się aktywność <a href=\"https://pl.wikipedia.org/wiki/S%C5%82o%C5%84ce\" target=\"_blank\" rel=\"noopener noreferrer\">Słońca</a>. Określenie służące do odmierzania przybliżonego czasu, wywodzące się z okresu w dziejach ludzkości gdy czas określany był na podstawie ruchu słońca. Jako początek poranka spotyka się definicje wiążącą go z bezpośrednim okresem po przebudzeniu osoby bardziej niż aktywnością słońca. Ten typ postrzegania poranka pojawił się wraz z pojawieniem się sztucznego oświetlenia i towarzyszącą mu niezależnością od naturalnego światła.", "Racisław": "<b>Racisław</b> — staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Raci-</i> (\"walczyć, wojować\") oraz <i>-sław</i> (\"sława\"). Może ono oznaczać \"sławnego wojownika\".", "Rita": "<b>Ryta</b>, również <b>Rita</b> – pierwotnie zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> żeńskich, zakończonych na <i>-rita</i>, zwłaszcza od imienia <i>Margarita</i> – <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a> (tak w przypadku aktorki <a href=\"https://pl.wikipedia.org/wiki/Rita_Hayworth\" target=\"_blank\" rel=\"noopener noreferrer\">Rity Hayworth</a>).", "Radociech": "<b>Radociech</b> – <a href=\"https://pl.wikipedia.org/wiki/Imiona_s%C5%82owia%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">słowiańskie</a>/<a href=\"https://pl.wikipedia.org/wiki/Dzieje_imion_w_Polsce\" target=\"_blank\" rel=\"noopener noreferrer\">staropolskie</a> <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członu <i>Rado-</i> (motywowany przez <i>rad</i> – \"być zadowolonym, chętnym, cieszyć się\" lub <i>radzić</i> – \"troszczyć się, dbać o coś\") oraz członu <i>-ciech</i> (\"cieszyć\"). Może ono oznaczać \"tego, który chętnie się cieszy\".", "Rodeo": "<b>Rodeo</b> – <a href=\"https://pl.wikipedia.org/wiki/Sport\" target=\"_blank\" rel=\"noopener noreferrer\">sport</a> wywodzący się z pracy z <a href=\"https://pl.wikipedia.org/wiki/Byd%C5%82o\" target=\"_blank\" rel=\"noopener noreferrer\">bydłem</a>, głównie w <a href=\"https://pl.wikipedia.org/wiki/Stany_Zjednoczone\" target=\"_blank\" rel=\"noopener noreferrer\">USA</a>, a także w <a href=\"https://pl.wikipedia.org/wiki/Hiszpania\" target=\"_blank\" rel=\"noopener noreferrer\">Hiszpanii</a> i <a href=\"https://pl.wikipedia.org/wiki/Australia\" target=\"_blank\" rel=\"noopener noreferrer\">Australii</a>. Bazuje ono na umiejętnościach wymaganych w pracy <a href=\"https://pl.wikipedia.org/wiki/Kowboj\" target=\"_blank\" rel=\"noopener noreferrer\">kowbojów</a>. Konkurencje, w większości rozgrywane z końskich grzbietów, mają sprawdzać umiejętności i refleks zawodników, a także odzwierciedlać dawny styl życia na <a href=\"https://pl.wikipedia.org/wiki/Zach%C3%B3d_Stan%C3%B3w_Zjednoczonych\" target=\"_blank\" rel=\"noopener noreferrer\">amerykańskim Zachodzie</a>. Polegają na rywalizacji w popisach we władaniu lassem, jeździe na bykach i niezajeżdżonych koniach, siłowaniu się z bykami itp.. Rodeo jest ściśle powiązane z <i><a href=\"https://pl.wikipedia.org/wiki/Western_riding\" target=\"_blank\" rel=\"noopener noreferrer\">Western riding</a></i>. Tradycyjnie przed rodeo odbywa się konna parada, często z udziałem wozów strażackich.", "Ruprecht": "<b>Robert</b>, <b>Rupert</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, z imienia Hrodebert. Wywodzi się od słów <i>hrod</i> (sława) oraz <i>beraht</i> (jasny, bystry), co oznacza „<i>ten, który jest sławny</i>”, „<i>ten, który żyje w chwale</i>” oraz „<i>ten, który oświeca noce</i>”.", "Rada": "<b>Rada</b> – <a href=\"https://pl.wikipedia.org/wiki/Kolegialno%C5%9B%C4%87\" target=\"_blank\" rel=\"noopener noreferrer\">kolegialny</a> organ składający się z grupy osób wybranych przez członków określonej <a href=\"https://pl.wikipedia.org/wiki/Grupa_spo%C5%82eczna\" target=\"_blank\" rel=\"noopener noreferrer\">społeczności</a> lub powołanych przez właściwe władze w celu reprezentowania interesów tej społeczności, podejmowania decyzji, opiniowania działań bądź doradzania w określonych kwestiach. Rada może mieć charakter instytucji formalnej, działającej w ramach określonej organizacji, <a href=\"https://pl.wikipedia.org/wiki/Jednostka_administracyjna\" target=\"_blank\" rel=\"noopener noreferrer\">jednostki administracyjnej</a> lub <a href=\"https://pl.wikipedia.org/wiki/Pa%C5%84stwo\" target=\"_blank\" rel=\"noopener noreferrer\">państwa</a>, albo pełnić funkcję ciała doradczego, którego zadaniem jest wypracowywanie rozwiązań poprzez dyskusję i wymianę doświadczeń jej członków. Zakres kompetencji rady zależy od kontekstu, w jakim działa – może ona m.in. pełnić funkcje <a href=\"https://pl.wikipedia.org/wiki/Legislacja\" target=\"_blank\" rel=\"noopener noreferrer\">legislacyjne</a>, <a href=\"https://pl.wikipedia.org/wiki/Kontrola_administracyjna\" target=\"_blank\" rel=\"noopener noreferrer\">kontrolne</a>, opiniodawcze lub organizacyjne. W szerszym znaczeniu rada jest grupą osób obradujących nad określonym problemem, aby wypracować decyzję lub udzielić wskazówek dotyczących dalszego postępowania.", "Rodan": "<b>Rodan</b> – męskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_celtyckie\" target=\"_blank\" rel=\"noopener noreferrer\">celtyckiego</a>, oboczna forma imienia <b>Ruadán</b>, które jest zdrobnieniem. Patronem imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Rodan_z_Lorrha\" target=\"_blank\" rel=\"noopener noreferrer\">Rodan z Lorrha</a>, apostoł Irlandii.", "Ratomir": "<b>Racimir</b>, <b>Racimiar</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> męskie, złożone z członów <i>Raci-</i> (\"walczyć, wojować\") oraz <i>-mir</i> (\"pokój, spokój, dobro\"). Znaczenie imienia: \"walczący o pokój\".", "Rasmussen": "<b>Rasmussen</b> – <a href=\"https://pl.wikipedia.org/wiki/Nazwisko_patronimiczne\" target=\"_blank\" rel=\"noopener noreferrer\">patronimiczne nazwisko</a> duńskie (9 miejsce) i norweskie (41 miejsce) , oznacza syna <a href=\"https://pl.wikipedia.org/wiki/Erazm\" target=\"_blank\" rel=\"noopener noreferrer\">Rasmusa</a>. W Danii w 1940 powstał film <i>Sørensen og Rasmussen</i>, gdzie <a href=\"https://pl.wikipedia.org/wiki/S%C3%B8rensen\" target=\"_blank\" rel=\"noopener noreferrer\">Sørensen</a> jest 8 nazwiskiem w tym kraju.", "Renata": "<b>Renata</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia łacińskiego. Oznacza odrodzona. Imię pojawiło się w Polsce w XVII wieku pod wpływami francuskimi.", "Regina": "<b>Regina</b> – imię żeńskie pochodzące od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a> słowa <i>regina</i> – <i>królowa</i>. Imię to nawiązuje do miana <i><a href=\"https://pl.wikipedia.org/wiki/Regina_Coeli\" target=\"_blank\" rel=\"noopener noreferrer\">Regina Coeli</a></i>, którym określa się Matkę Boską Królową Niebios. W <a href=\"https://pl.wikipedia.org/wiki/Polska\" target=\"_blank\" rel=\"noopener noreferrer\">Polsce</a> notowano je od XIV wieku.", "Róża": "<b>Róża</b> (<i>Rosa</i> <a href=\"https://pl.wikipedia.org/wiki/Karol_Linneusz\" target=\"_blank\" rel=\"noopener noreferrer\">L.</a>) – <a href=\"https://pl.wikipedia.org/wiki/Rodzaj_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">rodzaj</a> <a href=\"https://pl.wikipedia.org/wiki/Krzew\" target=\"_blank\" rel=\"noopener noreferrer\">krzewów</a> należących do rodziny <a href=\"https://pl.wikipedia.org/wiki/R%C3%B3%C5%BCowate\" target=\"_blank\" rel=\"noopener noreferrer\">różowatych</a> (<i>Rosaceae</i>). Znanych jest ok. 140–260 gatunków występujących na półkuli północnej. Występują w różnych formacjach leśnych i zaroślowych. Są <a href=\"https://pl.wikipedia.org/wiki/Krzew\" target=\"_blank\" rel=\"noopener noreferrer\">krzewami</a> i <a href=\"https://pl.wikipedia.org/wiki/Pn%C4%85cze\" target=\"_blank\" rel=\"noopener noreferrer\">pnączami</a> o kwiatach zwykle pachnących, zapylanych przez <a href=\"https://pl.wikipedia.org/wiki/Owady\" target=\"_blank\" rel=\"noopener noreferrer\">owady</a>.", "Rozalia": "<b>Rozalia</b> – imię żeńskie o niejasnej etymologii. Być może pochodzi od <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskich</a> słów <i>rosa</i> (róża) i <i>lilium</i> (lilia) lub od samego słowa <i>rosa</i>. Możliwe jest także pochodzenie germańskie, od germańskich imion dwuczłonowych z pierwszym członem <i>Roz-</i> (<i>Hros-</i>), zob. <a href=\"https://pl.wikipedia.org/wiki/Rozalinda\" target=\"_blank\" rel=\"noopener noreferrer\">Rozalinda</a>, <a href=\"https://pl.wikipedia.org/wiki/Rozamunda\" target=\"_blank\" rel=\"noopener noreferrer\">Rozamunda</a>, <a href=\"https://pl.wikipedia.org/wiki/Rozwita\" target=\"_blank\" rel=\"noopener noreferrer\">Rozwita</a>.", "Roksana": "<b>Roksana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>: <i>*Raṷxšnā</i> oznacza <i>blask</i>, <i>jutrzenka</i>, <i>jaśniejąca</i>. Do języków europejskich trafiło przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">grekę</a>, w której brzmienie imienia zanotowano jako Ῥωξάνη (<i>Roksane</i>).", "Romana": "<b>Romana</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Roman_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Roman</a>. Patronką tego imienia jest św. Romana, pustelnica żyjąca w grocie nieopodal rzeki <a href=\"https://pl.wikipedia.org/wiki/Tyber\" target=\"_blank\" rel=\"noopener noreferrer\">Tyber</a>, wspominana w jednej z biografii <a href=\"https://pl.wikipedia.org/wiki/Sylwester_I\" target=\"_blank\" rel=\"noopener noreferrer\">św. Sylwestra, papieża</a>.", "Romualda": "<b>Romualda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Romuald\" target=\"_blank\" rel=\"noopener noreferrer\">Romuald</a>, które oznacza „ten, który zdobył sławę dzięki swemu panowaniu”.", "Ryszarda": "<b>Ryszarda</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Ryszard\" target=\"_blank\" rel=\"noopener noreferrer\">Ryszard</a> pochodzenia germańskiego.", "Raisa": "<b>Raisa</b> – rosyjskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, występujące także w Polsce, przede wszystkim na obszarze, na którym zamieszkują mniejszości wyznające prawosławie (ponad 60% Rais mieszka w <a href=\"https://pl.wikipedia.org/wiki/Wojew%C3%B3dztwo_bia%C5%82ostockie_(1975%E2%80%931998)\" target=\"_blank\" rel=\"noopener noreferrer\">Białostockiem</a>), którego etymologia nie jest jasna. Podaje się różne warianty pochodzenia imienia: od <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki\" target=\"_blank\" rel=\"noopener noreferrer\">greckiego</a> <i>radia</i> – „lekka”; od gr. <i>reistos</i>, <i>radios</i> – „lekkomyślna, beztroska, niefrasobliwa” lub też przypisuje się jej znaczenie „wypoczęta”. Istnieją również przesłanki do utożsamienia tego imienia z imieniem Iraida (pod imieniem <i><b>Raisa (Iraida)</b></i> wymieniana jest ważna święta prawosławna), którego greckim wariantem jest Irais – por. Izis i <a href=\"https://pl.wikipedia.org/wiki/Izyda\" target=\"_blank\" rel=\"noopener noreferrer\">Izyda</a>. <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_rosyjski\" target=\"_blank\" rel=\"noopener noreferrer\">Ros.</a> Iraida pochodzi zaś od gr. <i>hērōis</i>, w <a href=\"https://pl.wikipedia.org/wiki/Dope%C5%82niacz_(przypadek)\" target=\"_blank\" rel=\"noopener noreferrer\">dop.</a> <i>hērōidos</i> – „heroina” (tj. „bohaterka”). Sposób utworzenia Raisy od heroiny byłby zatem analogiczny do przekształcenia, w wyniku którego z imienia Herodion powstał rosyjski wariant Rodion.", "Ruta": "<b>Ruta</b> (<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> רות <a href=\"https://pl.wikipedia.org/wiki/Rut\" target=\"_blank\" rel=\"noopener noreferrer\">Rut</a>, czyli wierna towarzyszka) – imię pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebrajskiego</a> występujące w biblijnej <a href=\"https://pl.wikipedia.org/wiki/Ksi%C4%99ga_Rut\" target=\"_blank\" rel=\"noopener noreferrer\">Księdze Rut</a>.", "Radosława": "<b>Radosława</b>, <b>Radsława</b>, <b>Redsława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członu <i>Rado-</i> (motywowanego przez <i>rad</i> – „być zadowolonym, chętnym, cieszyć się” lub <i>radzić</i> – „troszczyć się, dbać o coś”) oraz członu <i>-sława</i> („sława”). Może ono oznaczać „tę, która troszczy się o sławę” albo „tę, która jest chętna do zdobycia sławy”. W źródłach polskich poświadczone w XII wieku, a w innym źródle: od XIII wieku (1265 r.).", "Ryta": "<b>Ryta</b>, również <b>Rita</b> – pierwotnie zdrobnienie od <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imion</a> żeńskich, zakończonych na <i>-rita</i>, zwłaszcza od imienia <i>Margarita</i> – <a href=\"https://pl.wikipedia.org/wiki/Ma%C5%82gorzata_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Małgorzata</a> (tak w przypadku aktorki <a href=\"https://pl.wikipedia.org/wiki/Rita_Hayworth\" target=\"_blank\" rel=\"noopener noreferrer\">Rity Hayworth</a>).", "Rozwita": "<b>Rozwita</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a> (<i>Hroswitha</i>), oznaczające „sławna i silna” lub „słynąca z porywczości”. Patronką tego imienia jest św. <a href=\"https://pl.wikipedia.org/wiki/Hrotsvitha\" target=\"_blank\" rel=\"noopener noreferrer\">Hrotsvitha</a> (X wiek), zakonnica i <a href=\"https://pl.wikipedia.org/wiki/Mistycyzm\" target=\"_blank\" rel=\"noopener noreferrer\">mistyczka</a>.", "Rebeka": "<b>Rebeka</b>, także jako <b>Ryfka</b> – biblijne <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie z <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_hebrajski\" target=\"_blank\" rel=\"noopener noreferrer\">hebr.</a> <i>riwqah, ribhkah</i> o niejasnym znaczeniu. W Kościele katolickim istnieją święte i błogosławione o tym imieniu.", "Roberta": "<b>Roberta</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Robert_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Robert</a>.", "Rachela": "<i>A gdy wyruszyli z Betel i mieli jeszcze w drodze przed sobą pewną przestrzeń, aby dojść</i> <i>do Efrata, Rachela zaczęła rodzić; poród jednak był ciężki. I kiedy urodziła w wielkich bólach,</i> <i>rzekła do niej położna: «Już nie lękaj się, bo oto masz syna!» Ona jednak, gdy życie z niej</i> <i>uchodziło, bo konała, nazwała swego syna Benoni; lecz ojciec dał mu imię Beniamin</i>. <i>A Rachela umarła i została pochowana przy drodze do Efrata, czyli Betlejem. Jakub ustawił</i> <i>stelę na jej grobie. – Kamień ten stoi na grobie Racheli po dziś dzień.</i>", "Rafaela": "<b>Rafaela</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Rafa%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Rafał</a>.", "Rajmunda": "<b>Rajmunda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Zostało ono utworzone jako żeński odpowiednik męskiego imienia <a href=\"https://pl.wikipedia.org/wiki/Rajmund\" target=\"_blank\" rel=\"noopener noreferrer\">Rajmund</a>, składającego się z elementów znaczących pierwotnie „rada, zebranie” oraz „opieka, ochrona”.", "Rozanna": "<b>Roksana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_perski\" target=\"_blank\" rel=\"noopener noreferrer\">perskiego</a>: <i>*Raṷxšnā</i> oznacza <i>blask</i>, <i>jutrzenka</i>, <i>jaśniejąca</i>. Do języków europejskich trafiło przez <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_grecki_klasyczny\" target=\"_blank\" rel=\"noopener noreferrer\">grekę</a>, w której brzmienie imienia zanotowano jako Ῥωξάνη (<i>Roksane</i>).", "Rufina": "<b>Rufina</b> – żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Rufin\" target=\"_blank\" rel=\"noopener noreferrer\">Rufin</a>. Patronkami są dwie święte męczennice z III wieku.", "Radzisława": "<b>Radzisława</b> – żeńska forma <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Radzis%C5%82aw\" target=\"_blank\" rel=\"noopener noreferrer\">Radzisław</a>. Imię nienotowane w słownikach staropolskich. Człon <i>Radzi-</i> jest niespotykany w staropolskich imionach dwuczłonowych.", "Rusłana": "<b>Rusłana</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_turecki\" target=\"_blank\" rel=\"noopener noreferrer\">tureckiego</a>, forma żeńska imienia <a href=\"https://pl.wikipedia.org/wiki/Rus%C5%82an_(imi%C4%99)\" target=\"_blank\" rel=\"noopener noreferrer\">Rusłan</a>.", "Radomiła": "<b>Radomiła</b> – nienotowany w czasach staropolskich żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Radomi%C5%82\" target=\"_blank\" rel=\"noopener noreferrer\">Radomił</a>.", "Radochna": "<b>Radochna</b> – zdrobniała forma żeńska od imion żeńskich złożonych z pierwszym członem <i>Rado-</i> (<a href=\"https://pl.wikipedia.org/wiki/Radomira\" target=\"_blank\" rel=\"noopener noreferrer\">Radomira</a>, <a href=\"https://pl.wikipedia.org/wiki/Rados%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Radosława</a>). W źródłach polskich poświadczone od XIII wieku (1265 rok).", "Romania": "Nazwa wywodzi się z czasów po najeździe <a href=\"https://pl.wikipedia.org/wiki/Longobardowie\" target=\"_blank\" rel=\"noopener noreferrer\">Longobardów</a> na Italię, gdy podzielona została ona na część bizantyjską (Romanię) i longobardzką (<a href=\"https://pl.wikipedia.org/wiki/Lombardia\" target=\"_blank\" rel=\"noopener noreferrer\">Lombardię</a>). Romania wchodziła w skład bizantyjskiego <a href=\"https://pl.wikipedia.org/wiki/Egzarchat_Rawenny\" target=\"_blank\" rel=\"noopener noreferrer\">egzarchatu raweńskiego</a> - stopniowo znaczenie pojęcia „Romania” zawężyło się do obecnej krainy historycznej, która była ośrodkiem bizantyjskich posiadłości we Włoszech. Egzarchat raweński został podarowany <a href=\"https://pl.wikipedia.org/wiki/Papie%C5%BC\" target=\"_blank\" rel=\"noopener noreferrer\">papieżom</a> przez <a href=\"https://pl.wikipedia.org/wiki/Pepin_Kr%C3%B3tki\" target=\"_blank\" rel=\"noopener noreferrer\">Pepina Krótkiego</a> i pozostawał w ich władzy aż do <a href=\"https://pl.wikipedia.org/wiki/Zjednoczenie_W%C5%82och\" target=\"_blank\" rel=\"noopener noreferrer\">zjednoczenia Włoch</a>.", "Remigia": "<b>Remigia</b> - imię żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łacińskiego</a>, żeński odpowiednik imienia <a href=\"https://pl.wikipedia.org/wiki/Remigiusz\" target=\"_blank\" rel=\"noopener noreferrer\">Remigiusz</a>. Wywodzi się od łacińskiego rzeczownika <i>remigium</i>, oznaczającego \"wiosło\". Znaczenie imienia to \"wytwórca wioseł\".", "Randia": "<b>Randia</b> właściwie <b>Bronisława Korsun</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/1945\" target=\"_blank\" rel=\"noopener noreferrer\">1945</a> w <a href=\"https://pl.wikipedia.org/wiki/Ska%C5%82at\" target=\"_blank\" rel=\"noopener noreferrer\">Skałacie</a>) – polska piosenkarka pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Romowie\" target=\"_blank\" rel=\"noopener noreferrer\">romskiego</a>.", "Rasa": "<b>Rasa</b> – dostatecznie liczna grupa <a href=\"https://pl.wikipedia.org/wiki/Organizm\" target=\"_blank\" rel=\"noopener noreferrer\">organizmów</a> w obrębie jednego <a href=\"https://pl.wikipedia.org/wiki/Gatunek_(biologia)\" target=\"_blank\" rel=\"noopener noreferrer\">gatunku</a>, zdolna do rozmnażania w warunkach naturalnych, o wspólnym pochodzeniu i wspólnych cechach istotnych dla odróżnienia jej od innych organizmów tego gatunku. Rasa wykształca się samorzutnie lub zostaje wyhodowana przez człowieka w wyniku stosowanych metod hodowlanych.", "Rozalinda": "<b>Rozalinda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające „łagodny koń” i złożone z członów: <i>hros</i> – „koń” i <i>linde</i> – „łagodny, czuły” (por. <a href=\"https://pl.wikipedia.org/wiki/Adelinda\" target=\"_blank\" rel=\"noopener noreferrer\">Adelinda</a>). W późniejszym czasie łączono je z łacińską frazą <i>rosa linda</i> – „piękna róża”. Jest to imię bohaterki romansu <a href=\"https://pl.wikipedia.org/wiki/Thomas_Lodge\" target=\"_blank\" rel=\"noopener noreferrer\">Thomasa Lodge'a</a> <i>Rozalinda</i> i komedii <a href=\"https://pl.wikipedia.org/wiki/William_Shakespeare\" target=\"_blank\" rel=\"noopener noreferrer\">Szekspira</a> <i><a href=\"https://pl.wikipedia.org/wiki/Jak_wam_si%C4%99_podoba\" target=\"_blank\" rel=\"noopener noreferrer\">Jak wam się podoba</a></i>. W Kościele katolickim patronką tego imienia jest św.Roselina, mniszka (zm. 1329).", "Risa": "<b>Risa</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;りさ, リサ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Rosława": "<b>Rosława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, będące formą skróconą imienia <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bcis%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Rościsława</a> lub nienotowanego w danych źródłach w formie pełnej imienia <i><b>Rodsława</b></i>.", "Rudolfina": "<b>Rudolfina</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Rudolfa\" target=\"_blank\" rel=\"noopener noreferrer\">Rudolfa</a></b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imiona</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>; żeńskie odpowiedniki <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Rudolf\" target=\"_blank\" rel=\"noopener noreferrer\">Rudolf</a>, które wywodzi się od słów oznaczających \"sława wilka\". <b>Rudolfina</b> utworzona jest przy użyciu sufiksu <i>-ina</i>, który służył do tworzenia imion zdrobniałych (por. <a href=\"https://pl.wikipedia.org/wiki/Albertyna\" target=\"_blank\" rel=\"noopener noreferrer\">Albertyna</a>).", "Rościsława": "<b>Rościsława</b> – staropolskie <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie, złożone z członów <i>Rości-</i> (\"rośnie\") oraz <i>-sława</i> (\"sława\"). Może oznaczać \"ta, której sława rośnie\". Od tego imienia mogły pochodzić formy skrócone typu <a href=\"https://pl.wikipedia.org/wiki/Ros%C5%82awa\" target=\"_blank\" rel=\"noopener noreferrer\">Rosława</a>. W źródłach polskich poświadczone w XII wieku.", "Radomira": "<b>Radomira</b> – nienotowany w czasach staropolskich żeński odpowiednik <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Radomir\" target=\"_blank\" rel=\"noopener noreferrer\">Radomir</a>.", "Rhiannon": "Dziecko znalazł w swej stajni król <a href=\"https://pl.wikipedia.org/wiki/Teirnyon\" target=\"_blank\" rel=\"noopener noreferrer\">Teirnyon</a>, on i jego żona adoptowali je nadając mu imię - Gwri, \"Złote Włosy\". Gdy dziecko osiągnęło wiek dorosły, otrzymało źrebaka, który zaprowadził Teyrnona do stajni. Król dowiedział się, kim jest dziecko i zwrócił je Pwyllowi i Rhiannon, która nazwała je <a href=\"https://pl.wikipedia.org/wiki/Pryderi\" target=\"_blank\" rel=\"noopener noreferrer\">Pryderi</a>, co znaczy \"Zmartwienie\", gdyż przez cały czas jego nieobecności jej życie było pasmem udręk - fałszywie oskarżona o zamordowanie syna musiała w formie pokuty siedzieć przy bramie zamku Pwylla i opowiadać nieznajomym o swej zbrodni, po czym wnosiła ich na swych plecach do pałacu.", "Rie": "<b>Rie</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;りえ, リエ) – popularne <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Rozamunda": "<b>Rozamunda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>, oznaczające \"chroniąca rumaki\", od <i>hros</i> – \"rumak\" i <i>mund</i> – \"ochrona\". Później imię to łączono z łacińskimi słowami <i>rosa munda</i> – \"róża świata\", \"róża ludzkości\". Patronką tego imienia jest <a href=\"https://pl.wikipedia.org/wiki/Rozamunda_z_Blaru\" target=\"_blank\" rel=\"noopener noreferrer\">bł. Rozamunda</a> z <a href=\"https://pl.wikipedia.org/wiki/XII_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XII wieku</a>.", "Reika": "<b>Reika</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;れいか, レイカ) – żeńskie <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">imię japońskie</a>.", "Rym": "Rymy pełnią funkcję wierszotwórczą (wskazują koniec wersu, wzmacniają rytm, łączą wersy w <a href=\"https://pl.wikipedia.org/wiki/Strofa\" target=\"_blank\" rel=\"noopener noreferrer\">strofy</a>), instrumentacyjną (wpływają na kształt brzmieniowy utworu) i <a href=\"https://pl.wikipedia.org/wiki/Semantyka_(j%C4%99zykoznawstwo)\" target=\"_blank\" rel=\"noopener noreferrer\">semantyczną</a> (znaczeniową; uwypuklają znaczenia słów rymujących się). W poezji współczesnej rymy mają mniejsze znaczenie niż w tradycyjnej; w wielu zaś jej przejawach zupełnie nie występują.", "Ruti": "Para <a href=\"https://pl.wikipedia.org/wiki/Lew_afryka%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">lwów</a> zidentyfikowana z <a href=\"https://pl.wikipedia.org/wiki/Szu_(mitologia)\" target=\"_blank\" rel=\"noopener noreferrer\">Szu</a> i <a href=\"https://pl.wikipedia.org/wiki/Tefnut\" target=\"_blank\" rel=\"noopener noreferrer\">Tefnut</a>. Ruti miały szczególne znaczenie w wierzeniach w <a href=\"https://pl.wikipedia.org/wiki/%C5%BBycie_po%C5%9Bmiertne\" target=\"_blank\" rel=\"noopener noreferrer\">życie pozagrobowe</a>, gdyż do nich należały barki słoneczne, poranna i wieczorna. Zmarły identyfikując się z Ruti zyskiwał prawo do podróży wraz ze słońcem. Często w tekstach Ruti występuje jako jedna z form Re-Atuma i uważany jest za pojedynczą osobę.", "Raye": "<b>Raye</b> (zapis stylizowany: RAYE), właśc. <b>Rachel Agatha Keen</b> (ur. <a href=\"https://pl.wikipedia.org/wiki/24_pa%C5%BAdziernika\" target=\"_blank\" rel=\"noopener noreferrer\">24 października</a> <a href=\"https://pl.wikipedia.org/wiki/1997\" target=\"_blank\" rel=\"noopener noreferrer\">1997</a> w <a href=\"https://pl.wikipedia.org/wiki/Londyn\" target=\"_blank\" rel=\"noopener noreferrer\">Londynie</a>) – <a href=\"https://pl.wikipedia.org/wiki/Anglicy\" target=\"_blank\" rel=\"noopener noreferrer\">angielska</a> <a href=\"https://pl.wikipedia.org/wiki/Piosenkarz\" target=\"_blank\" rel=\"noopener noreferrer\">piosenkarka</a>, producentka i autorka tekstów pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ghana\" target=\"_blank\" rel=\"noopener noreferrer\">ghańsko</a>-<a href=\"https://pl.wikipedia.org/wiki/Szwajcaria\" target=\"_blank\" rel=\"noopener noreferrer\">szwajcarskiego</a>.", "Rudolfa": "<b>Rudolfa</b>, <b><a href=\"https://pl.wikipedia.org/wiki/Rudolfina\" target=\"_blank\" rel=\"noopener noreferrer\">Rudolfina</a></b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imiona</a> pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>; żeńskie odpowiedniki <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imienia</a> <a href=\"https://pl.wikipedia.org/wiki/Rudolf\" target=\"_blank\" rel=\"noopener noreferrer\">Rudolf</a>, które wywodzi się od słów oznaczających \"sława wilka\".", "Ruri": "<b>Ruri</b>&#32;(<a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">jap.</a>&#32;るり, ルリ) – <a href=\"https://pl.wikipedia.org/wiki/Imiona_japo%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">żeńskie imię japońskie</a>.", "Rzepicha": "Postać Rzepichy pojawiała się w źródłach zawsze obok męża, a jej wątek nie był rozbudowywany. Samo imię ma formę zdrobniałą i pochodzi od <a href=\"https://pl.wikipedia.org/wiki/Rzepa\" target=\"_blank\" rel=\"noopener noreferrer\">rzepy</a> z przyrostkiem pomniejszającym.", "Rufa": "<b>Rufa</b> – tylna część <a href=\"https://pl.wikipedia.org/wiki/Jednostka_p%C5%82ywaj%C4%85ca\" target=\"_blank\" rel=\"noopener noreferrer\">jednostki pływającej</a>, zarówno w jej części nawodnej, jak i podwodnej. Istnieje wiele rodzajów form konstrukcyjnych ruf. Wraz z rozwojem <a href=\"https://pl.wikipedia.org/wiki/%C5%BBegluga\" target=\"_blank\" rel=\"noopener noreferrer\">żeglugi</a> ulegały one modyfikacjom zarówno ze względu na wykorzystywany materiał, przeznaczenie statku, jak i panującą w danych czasach modę. Rufa może być zakończona <a href=\"https://pl.wikipedia.org/wiki/Paw%C4%99%C5%BC_(%C5%BCegluga)\" target=\"_blank\" rel=\"noopener noreferrer\">pawężą</a> zorientowaną prostopadle względem lustra wody lub pochyloną w kierunku rufy, czy <a href=\"https://pl.wikipedia.org/wiki/Dzi%C3%B3b_jednostki_p%C5%82ywaj%C4%85cej\" target=\"_blank\" rel=\"noopener noreferrer\">dziobu</a> jednostki. Rufa może wystawać nad powierzchnię wody, tworząc <a href=\"https://pl.wikipedia.org/wiki/Nawis_rufowy\" target=\"_blank\" rel=\"noopener noreferrer\">nawis rufowy</a>.", "Radegunda": "<b>Radegunda</b> – <a href=\"https://pl.wikipedia.org/wiki/Imi%C4%99\" target=\"_blank\" rel=\"noopener noreferrer\">imię</a> żeńskie pochodzenia <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyki_germa%C5%84skie\" target=\"_blank\" rel=\"noopener noreferrer\">germańskiego</a>. Wywodzi się od imienia <i>Radegund</i>, składającego się ze słów <i>rad</i> „porada, rada” oraz <i>gund</i> „walka”. W Polsce spotykane rzadko, również jako <b>Radigunda</b> i <b>Radygunda</b>.", "Rycheza": "<b>Ryksa</b>, <b>Rycheza</b> – imię żeńskie pochodzenia germańskiego.", "Ronna": "<b>Ronna</b> (<b>R</b>) – przedrostek <a href=\"https://pl.wikipedia.org/wiki/Jednostka_miary\" target=\"_blank\" rel=\"noopener noreferrer\">jednostek miary</a> oznaczający mnożnik 1 000 000 000 000 000 000 000 000 000 = 10 (<a href=\"https://pl.wikipedia.org/wiki/Kwadryliard\" target=\"_blank\" rel=\"noopener noreferrer\">kwadryliard</a>). Rezolucja wprowadzająca przedrostek została przyjęta na 27. posiedzeniu <a href=\"https://pl.wikipedia.org/wiki/Generalna_Konferencja_Miar\" target=\"_blank\" rel=\"noopener noreferrer\">Generalnej Konferencji Miar</a> w listopadzie 2022 roku.", "Ras": "<b>Ras</b> (w <a href=\"https://pl.wikipedia.org/wiki/J%C4%99zyk_amharski\" target=\"_blank\" rel=\"noopener noreferrer\">języku amharskim</a> <b>głowa</b>) – jeden z najwyższych tytułów arystokratycznych w cesarskiej <a href=\"https://pl.wikipedia.org/wiki/Etiopia\" target=\"_blank\" rel=\"noopener noreferrer\">Etiopii</a>, utworzony najprawdopodobniej podczas reformy wojskowej w czasie wojen z <a href=\"https://pl.wikipedia.org/wiki/Ahmad_ibn_Ibrihim_al-Ghazi\" target=\"_blank\" rel=\"noopener noreferrer\">Graniem</a> <a href=\"https://pl.wikipedia.org/wiki/XVI_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XVI w.</a>, pierwotnie najwyższy tytuł w hierarchii wojskowej, przyznawany zwykle – wyłącznie przez <a href=\"https://pl.wikipedia.org/wiki/Cesarz\" target=\"_blank\" rel=\"noopener noreferrer\">cesarza</a> (<a href=\"https://pl.wikipedia.org/wiki/Negus\" target=\"_blank\" rel=\"noopener noreferrer\">negusa</a>) – zarządcom wielkich prowincji. Prawo do posługiwania się tytułem rasa mieli także zwierzchnicy <a href=\"https://pl.wikipedia.org/wiki/Ko%C5%9Bci%C3%B3%C5%82_etiopski\" target=\"_blank\" rel=\"noopener noreferrer\">kościoła etiopskiego</a>. Częściej tytuł rasa zaczęto przyznawać w <a href=\"https://pl.wikipedia.org/wiki/XIX_wiek\" target=\"_blank\" rel=\"noopener noreferrer\">XIX w.</a> jako tytuł arystokratyczny, przy czym zachowywano zasadę, że człowiek, noszący ten tytuł powinien wywodzić się z feudalnego rodu arystokratycznego lub rodziny cesarskiej (odpowiednik <i>księcia</i>). Cesarz <a href=\"https://pl.wikipedia.org/wiki/Menelik_II\" target=\"_blank\" rel=\"noopener noreferrer\">Menelik II</a> (<a href=\"https://pl.wikipedia.org/wiki/1844\" target=\"_blank\" rel=\"noopener noreferrer\">1844</a>–<a href=\"https://pl.wikipedia.org/wiki/1911\" target=\"_blank\" rel=\"noopener noreferrer\">1911</a>) miał prawo przyznawać tytuł rasa zarządcom 20 prowincji.", "Rahab": "Według <a href=\"https://pl.wikipedia.org/wiki/Biblia\" target=\"_blank\" rel=\"noopener noreferrer\">literatury biblijnej</a> był to mityczny smok chaosu, którego pokonał i zgładził Bóg, co stanowiło okazję do sławienia Go jako zwycięzcy. Miano to oznaczało również uosobienie wód pierwotnych (<a href=\"https://pl.wikipedia.org/wiki/Tiamat\" target=\"_blank\" rel=\"noopener noreferrer\">Tiamat</a>). W podobnym charakterze pojawiały się w piśmiennictwie biblijnym stwory takie jak <a href=\"https://pl.wikipedia.org/wiki/Lewiatan_(potw%C3%B3r)\" target=\"_blank\" rel=\"noopener noreferrer\">Lewiatan</a> oraz Tannin&#65279;<a href=\"https://www.wikidata.org/wiki/Q2393094#sitelinks-wikipedia\" target=\"_blank\" rel=\"noopener noreferrer\">(inne języki)</a>.", "Ramat": "Jest terminem wieloznacznym, w zależności od kontekstu oznaczającym <a href=\"https://pl.wikipedia.org/wiki/Dusza_(religia)\" target=\"_blank\" rel=\"noopener noreferrer\">duszę</a>, wszelkie procesy myślowe, serce czy intelekt. Czasem o ramat wspomina się jako o esencji wszelkiego życia. Zgodnie z wierzeniami Ajnów wszystkie istoty, wszelkie nieożywione elementy przyrody, a także przedmioty wytworzone przez człowieka posiadały ramat. Jego utrata oznaczała kres istnienia danego stworzenia lub przedmiotu.", "Ruifang": "Populacja dzielnicy Ruifang w 2016 roku liczyła 40&#160;600 mieszkańców – 20&#160;082 kobiety i 20&#160;518 mężczyzn. Liczba gospodarstw domowych wynosiła 16&#160;168, co oznacza, że w jednym gospodarstwie zamieszkiwało średnio 2,51 osób.", "Rutyna": "<b>Rutyna</b>, <b>rutozyd</b> (<a href=\"https://pl.wikipedia.org/wiki/%C5%81acina\" target=\"_blank\" rel=\"noopener noreferrer\">łac.</a>&#160;<em>rutosidum</em>) – <a href=\"https://pl.wikipedia.org/wiki/Zwi%C4%85zki_organiczne\" target=\"_blank\" rel=\"noopener noreferrer\">organiczny związek chemiczny</a> z grupy glikozydów <a href=\"https://pl.wikipedia.org/wiki/Flawonoidy\" target=\"_blank\" rel=\"noopener noreferrer\">flawonoidowych</a>. Naturalny związek pochodzenia <a href=\"https://pl.wikipedia.org/wiki/Ro%C5%9Bliny\" target=\"_blank\" rel=\"noopener noreferrer\">roślinnego</a>, pozyskiwany z kwiatów <a href=\"https://pl.wikipedia.org/wiki/Pere%C5%82kowiec_japo%C5%84ski\" target=\"_blank\" rel=\"noopener noreferrer\">perełkowca japońskiego</a> (<i>Styphnolobium japonicum</i>) i z ziela <a href=\"https://pl.wikipedia.org/wiki/Gryka\" target=\"_blank\" rel=\"noopener noreferrer\">gryki</a> (<i>Fagopyrum esculentum</i>). Po raz pierwszy rutyna została wyizolowana z ziela <a href=\"https://pl.wikipedia.org/wiki/Ruta_zwyczajna\" target=\"_blank\" rel=\"noopener noreferrer\">ruty zwyczajnej</a> (stąd nazwa). Jest czasami błędnie nazywana <a href=\"https://pl.wikipedia.org/wiki/Witamina_P\" target=\"_blank\" rel=\"noopener noreferrer\">witaminą P</a>.", "Radocha": "Przecięta torowiskiem historycznej <a href=\"https://pl.wikipedia.org/wiki/Kolej_Iwangorodzko-D%C4%85browska\" target=\"_blank\" rel=\"noopener noreferrer\">Kolei Iwangorodzko-Dąbrowskiej</a> nie posiadającym tutaj stacji i rzadko już używanym na tym odcinku, jednak dzięki któremu ówcześnie nabrała istotnego znaczenia gospodarczego."};
